// Pulls metrics from your manual exit entries
const entry_price = parseFloat($json.entry_price) || 0;
const exit_price = parseFloat($json.exit_price) || 0;
const quantity = parseInt($json.quantity) || 0;

const buy_value  = entry_price * quantity;
const sell_value = exit_price * quantity;
const gross_profit = sell_value - buy_value;

// Exact Indian equity intraday transaction fee structures
const brokerage = Math.min(20, buy_value * 0.0003) * 2; // Buy + Sell cap
const stt       = sell_value * 0.00025;                 // Intraday STT
const gst       = brokerage * 0.18;                     // 18% GST on brokerage
const exchange  = (buy_value + sell_value) * 0.0000345;  // NSE txn charge
const sebi      = (buy_value + sell_value) * 0.000001;   // SEBI turnover tax
const stamp     = buy_value * 0.00015;                  // Stamp duty

const total_charges = brokerage + stt + gst + exchange + sebi + stamp;
const net_profit = gross_profit - total_charges;
const return_pct = buy_value > 0 ? (Math.round((net_profit / buy_value) * 10000) / 100) : 0;

return [{ json: {
  ...$json,
  buy_value: Math.round(buy_value),
  sell_value: Math.round(sell_value),
  gross_profit: Math.round(gross_profit * 100) / 100,
  brokerage: Math.round(brokerage * 100) / 100,
  stt: Math.round(stt * 100) / 100,
  gst: Math.round(gst * 100) / 100,
  exchange: Math.round(exchange * 100) / 100,
  sebi: Math.round(sebi * 100) / 100,
  stamp: Math.round(stamp * 100) / 100,
  total_charges: Math.round(total_charges * 100) / 100,
  net_profit: Math.round(net_profit * 100) / 100,
  return_pct: return_pct
}}];
